-- Phase 1 MVP Database Schema for Barbershop SaaS\n-- Deploy to Supabase via SQL Editor\n\n-- Enable extensions\nCREATE EXTENSION IF NOT EXISTS \"uuid-ossp\";\nCREATE EXTENSION IF NOT EXISTS \"pg_trgm\";\n\n-- ============================================\n-- 1. CORE TABLES\n-- ============================================\n\n-- Barbershops (single for MVP, multi-tenant in Phase 3)\nCREATE TABLE IF NOT EXISTS barbershops (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  name VARCHAR(255) NOT NULL,\n  owner_id UUID NOT NULL,\n  email VARCHAR(255),\n  phone VARCHAR(20),\n  address TEXT,\n  city VARCHAR(100),\n  state VARCHAR(2),\n  zip_code VARCHAR(10),\n  opening_time TIME DEFAULT '09:00',\n  closing_time TIME DEFAULT '19:00',\n  timezone VARCHAR(50) DEFAULT 'America/Sao_Paulo',\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Barbers (employees)\nCREATE TABLE IF NOT EXISTS barbers (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  barbershop_id UUID NOT NULL REFERENCES barbershops(id) ON DELETE CASCADE,\n  user_id UUID NOT NULL,\n  name VARCHAR(255) NOT NULL,\n  email VARCHAR(255),\n  phone VARCHAR(20),\n  bio TEXT,\n  avatar_url VARCHAR(500),\n  specialties TEXT[] DEFAULT ARRAY[]::TEXT[],\n  is_active BOOLEAN DEFAULT true,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Services (haircut types)\nCREATE TABLE IF NOT EXISTS services (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  barbershop_id UUID NOT NULL REFERENCES barbershops(id) ON DELETE CASCADE,\n  name VARCHAR(255) NOT NULL,\n  description TEXT,\n  duration_minutes INTEGER NOT NULL DEFAULT 30,\n  base_price DECIMAL(10, 2) NOT NULL,\n  is_active BOOLEAN DEFAULT true,\n  icon_emoji VARCHAR(10),\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Pricing per barber per service (allows different prices)\nCREATE TABLE IF NOT EXISTS pricing (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  barber_id UUID NOT NULL REFERENCES barbers(id) ON DELETE CASCADE,\n  service_id UUID NOT NULL REFERENCES services(id) ON DELETE CASCADE,\n  price DECIMAL(10, 2) NOT NULL,\n  commission_percent DECIMAL(5, 2) DEFAULT 60,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n  UNIQUE(barber_id, service_id)\n);\n\n-- Barber Schedules (availability)\nCREATE TABLE IF NOT EXISTS barber_schedules (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  barber_id UUID NOT NULL REFERENCES barbers(id) ON DELETE CASCADE,\n  day_of_week INTEGER NOT NULL CHECK (day_of_week >= 0 AND day_of_week <= 6),\n  start_time TIME NOT NULL,\n  end_time TIME NOT NULL,\n  is_working BOOLEAN DEFAULT true,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n  UNIQUE(barber_id, day_of_week)\n);\n\n-- Bookings (core business logic)\nCREATE TABLE IF NOT EXISTS bookings (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  barbershop_id UUID NOT NULL REFERENCES barbershops(id) ON DELETE CASCADE,\n  barber_id UUID NOT NULL REFERENCES barbers(id) ON DELETE CASCADE,\n  service_id UUID NOT NULL REFERENCES services(id) ON DELETE CASCADE,\n  client_id UUID NOT NULL,\n  client_name VARCHAR(255) NOT NULL,\n  client_phone VARCHAR(20),\n  client_email VARCHAR(255),\n  booking_date DATE NOT NULL,\n  booking_time TIME NOT NULL,\n  duration_minutes INTEGER NOT NULL DEFAULT 30,\n  total_price DECIMAL(10, 2),\n  barber_commission DECIMAL(10, 2),\n  status VARCHAR(50) DEFAULT 'confirmed' CHECK (status IN ('pending', 'confirmed', 'completed', 'cancelled', 'no-show')),\n  notes TEXT,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Clients (customer records)\nCREATE TABLE IF NOT EXISTS clients (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  barbershop_id UUID NOT NULL REFERENCES barbershops(id) ON DELETE CASCADE,\n  name VARCHAR(255) NOT NULL,\n  phone VARCHAR(20) UNIQUE NOT NULL,\n  email VARCHAR(255),\n  total_visits INTEGER DEFAULT 0,\n  total_spent DECIMAL(10, 2) DEFAULT 0,\n  preferred_barber_id UUID REFERENCES barbers(id) ON DELETE SET NULL,\n  preferred_service_id UUID REFERENCES services(id) ON DELETE SET NULL,\n  is_active BOOLEAN DEFAULT true,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Cut History (analytics)\nCREATE TABLE IF NOT EXISTS cut_history (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  barbershop_id UUID NOT NULL REFERENCES barbershops(id) ON DELETE CASCADE,\n  barber_id UUID NOT NULL REFERENCES barbers(id) ON DELETE CASCADE,\n  service_id UUID NOT NULL REFERENCES services(id) ON DELETE CASCADE,\n  client_phone VARCHAR(20),\n  price DECIMAL(10, 2) NOT NULL,\n  commission DECIMAL(10, 2),\n  cut_date DATE NOT NULL,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Notifications\nCREATE TABLE IF NOT EXISTS notifications (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  booking_id UUID NOT NULL REFERENCES bookings(id) ON DELETE CASCADE,\n  recipient_type VARCHAR(50) CHECK (recipient_type IN ('client', 'barber', 'admin')),\n  recipient_phone VARCHAR(20),\n  recipient_email VARCHAR(255),\n  notification_type VARCHAR(50) CHECK (notification_type IN ('confirmation', 'reminder', 'cancellation', 'completed')),\n  channel VARCHAR(50) DEFAULT 'email' CHECK (channel IN ('email', 'sms', 'whatsapp')),\n  sent_at TIMESTAMP WITH TIME ZONE,\n  status VARCHAR(50) DEFAULT 'pending' CHECK (status IN ('pending', 'sent', 'failed')),\n  retry_count INTEGER DEFAULT 0,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\n-- ============================================\n-- 2. BUSINESS RULES TABLE\n-- ============================================\n\nCREATE TABLE IF NOT EXISTS barbershop_settings (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  barbershop_id UUID NOT NULL UNIQUE REFERENCES barbershops(id) ON DELETE CASCADE,\n  booking_buffer_minutes INTEGER DEFAULT 0,\n  cancellation_deadline_hours INTEGER DEFAULT 24,\n  reminder_hours_before INTEGER DEFAULT 24,\n  allow_same_day_booking BOOLEAN DEFAULT true,\n  max_concurrent_bookings INTEGER DEFAULT 1,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\n-- ============================================\n-- 3. ANALYTICS TABLES\n-- ============================================\n\nCREATE TABLE IF NOT EXISTS daily_revenue (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  barbershop_id UUID NOT NULL REFERENCES barbershops(id) ON DELETE CASCADE,\n  revenue_date DATE NOT NULL,\n  total_revenue DECIMAL(10, 2) DEFAULT 0,\n  total_bookings INTEGER DEFAULT 0,\n  completed_bookings INTEGER DEFAULT 0,\n  cancelled_bookings INTEGER DEFAULT 0,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n  UNIQUE(barbershop_id, revenue_date)\n);\n\n-- ============================================\n-- 4. INDICES FOR PERFORMANCE\n-- ============================================\n\nCREATE INDEX idx_bookings_barber_date ON bookings(barber_id, booking_date);\nCREATE INDEX idx_bookings_barbershop_date ON bookings(barbershop_id, booking_date);\nCREATE INDEX idx_bookings_status ON bookings(status);\nCREATE INDEX idx_bookings_created ON bookings(created_at DESC);\nCREATE INDEX idx_clients_barbershop ON clients(barbershop_id);\nCREATE INDEX idx_clients_phone ON clients(phone);\nCREATE INDEX idx_cut_history_barber_date ON cut_history(barber_id, cut_date);\nCREATE INDEX idx_cut_history_date ON cut_history(cut_date DESC);\nCREATE INDEX idx_notifications_booking ON notifications(booking_id);\nCREATE INDEX idx_notifications_status ON notifications(status);\n\n-- ============================================\n-- 5. AUTH & USERS (Keycloak linked)\n-- ============================================\n\nCREATE TABLE IF NOT EXISTS user_roles (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  keycloak_user_id UUID NOT NULL,\n  barbershop_id UUID NOT NULL REFERENCES barbershops(id) ON DELETE CASCADE,\n  role VARCHAR(50) NOT NULL CHECK (role IN ('owner', 'admin', 'barber', 'client')),\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n  UNIQUE(keycloak_user_id, barbershop_id, role)\n);\n\nCREATE INDEX idx_user_roles_keycloak ON user_roles(keycloak_user_id);\nCREATE INDEX idx_user_roles_barbershop ON user_roles(barbershop_id);\n\n-- ============================================\n-- 6. ROW-LEVEL SECURITY (RLS) POLICIES\n-- ============================================\n\nALTER TABLE barbershops ENABLE ROW LEVEL SECURITY;\nALTER TABLE barbers ENABLE ROW LEVEL SECURITY;\nALTER TABLE services ENABLE ROW LEVEL SECURITY;\nALTER TABLE pricing ENABLE ROW LEVEL SECURITY;\nALTER TABLE bookings ENABLE ROW LEVEL SECURITY;\nALTER TABLE clients ENABLE ROW LEVEL SECURITY;\nALTER TABLE notifications ENABLE ROW LEVEL SECURITY;\nALTER TABLE user_roles ENABLE ROW LEVEL SECURITY;\n\n-- Note: RLS policies are configured in separate migration file\n-- See: rls_policies.sql\n\nCOMMIT;\n", "path": "supabase/migrations/20260526_initial_schema.sql"